const crypto = require('crypto');
const secret = $env.REVIEW_HMAC_SECRET || 'fallback-secret';

const params = $input.first().json.query || {};
const groupCode = params.group;
const fy        = params.fy;
const resp      = params.resp;
const token     = params.token;

if (!groupCode || !fy || !resp || !token) {
  return [{ json: { valid: false, error: 'Missing required parameters' } }];
}

if (resp !== 'YES' && resp !== 'NO') {
  return [{ json: { valid: false, error: 'Invalid response value' } }];
}

const expected = crypto.createHmac('sha256', secret)
  .update(`${groupCode}|${fy}|${resp}`)
  .digest('hex');

const valid = expected === token;
return [{ json: { valid, groupCode, fy_year: parseInt(fy), resp, token } }];

// Collect results from the UPDATE RETURNING
const rows = $input.all().filter(r => r.json && r.json.item_id != null);
const count = rows.length;

if (count === 0) {
  // No rows updated — group not found or FY mismatch
  const html = `<!DOCTYPE html>
<html>
<head><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:40px 20px;background:#f9fafb;text-align:center">
  <div style="max-width:420px;margin:0 auto;background:#fff;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.1);padding:40px 32px">
    <h2 style="color:#dc2626">Nothing updated</h2>
    <p style="color:#555">This checklist group was not found for the given FY. The link may be outdated.</p>
  </div>
</body>
</html>`;
  return [{ json: { html } }];
}

const first        = rows[0].json;
const question     = first.applicability_question;
const resp         = first.is_applicable;
const isYes        = resp === 'YES';
const colour       = isYes ? '#16a34a' : '#dc2626';
const icon         = isYes ? '&#10003;' : '&#10007;';
const verb         = isYes ? 'YES — applicable' : 'NO — not applicable';
const itemsUpdated = count === 1 ? '1 checklist item' : `${count} checklist items`;

const html = `<!DOCTYPE html>
<html>
<head><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:40px 20px;background:#f9fafb;text-align:center">
<div style="max-width:440px;margin:0 auto;background:#fff;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.1);padding:40px 32px">
  <div style="width:64px;height:64px;border-radius:50%;background:${colour};margin:0 auto 20px;display:flex;align-items:center;justify-content:center">
    <span style="color:#fff;font-size:32px;line-height:1">${icon}</span>
  </div>
  <h2 style="margin:0 0 8px;color:#111">Response recorded</h2>
  <p style="color:#555;margin:0 0 8px;font-size:15px">${question}</p>
  <p style="color:${colour};font-weight:700;font-size:16px;margin:0 0 20px">${verb}</p>
  <p style="color:#94a3b8;font-size:12px;margin:0 0 24px">${itemsUpdated} updated</p>
  <a href="https://n8n.rodinah.dev" style="background:#1e40af;color:#fff;padding:10px 20px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:600">
    &#8592; Back to Checklist
  </a>
</div>
</body>
</html>`;

return [{ json: { html } }];
